    public (bool Status, string Msg, string Token, User_Class User) Login(string account, string inPassword)
    {
        try
        {
            var user = GetUserByAccount(account).FirstOrDefault();

            if (user == null)
            {
                return (false, "invalid user", "", user);
            }

            if (user.Status != 11)
            {
                return (false, "blocked user", "", user);
            }

            if (!PasswordTest(user, inPassword)) //验证密码失败
            {
                return (false, "wrong password", "", user);
            }

            var (status, msg, token) = TokenBusiness.TokenGet(user.Account, user);

            return (status, msg, token, user);

        }
        catch (Exception ex)
        {
            Logger.Error("获取token\r\n" + ex.ToString());
            return (false, ex.Message, "", null);
        }
    }

