        var authUser = tempAuthUser[0];
        authUser.Password = MakeSaltPassword(authUser, newPass);
        authUser.Update_time = FunCommon.GetStandardTimeStamp();

        var res = Update(authUser);

        return (res, res ? "success" : "failed");
    }

